package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.util.Collections;
import java.util.List;

import org.junit.jupiter.api.Test;

class CartTest {

  // Dummy LineItem class to fix compilation error
  static class LineItem {}

  @Test
  void testGetBuyerName() {
    List<LineItem> lineItems = Collections.emptyList();
    String buyerName = "John Doe";
    String creditCard = "1234-5678-9876-5432";

    Cart cart = new Cart(lineItems, buyerName, creditCard);

    assertEquals(buyerName, cart.getBuyerName());
  }
}
